// --- Source 1: YouTube (from previous node) ---
let ytItems = [];
try {
  const ytResp = $input.first().json;
  for (const v of (ytResp.items || [])) {
    const sn = v.snippet || {};
    if (sn.title) ytItems.push({ topic: sn.title.trim(), source: 'youtube_trending', tags: sn.tags || [] });
  }
} catch(e) { console.log('YouTube parse failed:', e.message); }

// --- Source 2: Google Trends Daily RSS ---
let trendsItems = [];
try {
  const r = await $http.get('https://trends.google.com/trends/trendingsearches/daily/rss?geo=IN');
  const xml = typeof r.data === 'string' ? r.data : JSON.stringify(r.data);
  const matches = [...xml.matchAll(/<title>(?:<!\[CDATA\[)?([^<\]]+?)(?:\]\]>)?<\/title>/g)];
  for (const m of matches.slice(1)) {
    const t = m[1].trim();
    if (t) trendsItems.push({ topic: t, source: 'google_trends_daily', tags: [] });
  }
} catch(e) { console.log('Trends RSS failed:', e.message); }

// --- Source 3: Google News RSS ---
let newsItems = [];
try {
  const r = await $http.get('https://news.google.com/rss?hl=en-IN&gl=IN&ceid=IN:en');
  const xml = typeof r.data === 'string' ? r.data : JSON.stringify(r.data);
  const matches = [...xml.matchAll(/<title>(?:<!\[CDATA\[)?([^<\]]+?)(?:\]\]>)?<\/title>/g)];
  for (const m of matches.slice(1, 101)) {
    const t = m[1].trim();
    if (t) newsItems.push({ topic: t, source: 'google_news_rss', tags: [] });
  }
} catch(e) { console.log('News RSS failed:', e.message); }

// --- Scoring constants (mirrors trending_india_pipeline.py) ---
const T1 = ['buy','price','cheap','best','review','order','shop','deal','discount','sale','offer','coupon','promo code','clearance','cash on delivery','cod','free shipping','emi','in stock','where to buy','lowest price','cheap price','wholesale','bulk','dropship','distributor','under 500','under 1000'];
const T2 = ['alternative to','similar to','replacement for','specs','specifications','features','dimensions','unboxing','hands on','teardown','pros and cons','is it worth it','buying guide','top 10','top 5','tier list','ranking','benchmarks','reddit','quora','combo','kit','pack','vs','comparison'];
const T3 = ['wireless','portable','new','latest','trending','india 2026','original','authentic','genuine','fake vs real','refurbished','second hand','used','open box','warranty','return policy','customer service','size chart','colors','variants','edition','flash sale','limited time','lightning deal','restock','sold out','in stock tracker','pre-order','launch date','release date','early access','near me'];
const NEG = ['how to','tutorial','diy','repair','fix','not working','error','broken','manual','pdf','driver download','free download'];
const CAT = {
  electronics: ['wireless','bluetooth','earbuds','phone','laptop','usb','charger','led','power bank','smartwatch','speaker','monitor','cable','adapter','tablet','camera'],
  fashion: ['shirt','dress','kurta','saree','sneakers','watch','bag','sunglasses','jeans','t-shirt','jacket','shoes','hoodie','heels','wallet','belt'],
  home: ['kitchen','decor','organizer','cleaning','storage','fan','cooler','light','bottle','bedsheet','pillow','cookware','blender','mop','towel','vacuum'],
  fitness: ['gym','yoga','protein','supplement','band','tracker','cycle','dumbbells','mat','creatine','whey','treadmill','resistance','shaker','massager'],
  beauty: ['skincare','hair','serum','moisturizer','lipstick','foundation','sunscreen','shampoo','perfume','lotion','concealer','trimmer','face wash','makeup','cleanser'],
  accessories: ['case','cover','stand','holder','mount','strap','tempered glass','sleeve','skin','guard','ring','tripod','grip','hub'],
  automotive: ['car','bike','helmet','dashcam','tyre','wax','polish','wiper','gps','inflator','mat','coolant','scratch','jump starter','perfume'],
  baby_and_kids: ['toy','puzzle','lego','diaper','stroller','wipes','pacifier','onesie','rattle','plush','scooter','doll','action figure','bottle'],
  pets: ['dog','cat','food','collar','leash','bed','litter','treats','aquarium','grooming','cage','harness','shampoo','bowl'],
  office_and_stationery: ['book','notebook','pen','desk','chair','printer','paper','marker','folder','diary','planner','stapler','calculator','ink'],
  health_and_medical: ['thermometer','massager','vitamins','mask','sanitizer','first aid','scale','oximeter','braces','monitor','inhaler','test kit','support'],
  tools_and_hardware: ['drill','screwdriver','wrench','saw','tape','hammer','screws','pliers','multimeter','ladder','glue','toolkit','nails','hinge'],
  grocery_and_food: ['coffee','tea','snacks','chocolate','dry fruits','oil','rice','spices','honey','noodles','sauce','cereal','pasta','biscuit']
};
const STOP = new Set(['a','an','the','in','of','for','with','is','are','was','were','and','or','on','at','to','by','from']);

function scoreIntent(topic, related) {
  const h = [topic, ...related].join(' ').toLowerCase();
  let s = 0;
  T1.forEach(p => { if (h.includes(p)) s += 0.30; });
  T2.forEach(p => { if (h.includes(p)) s += 0.15; });
  T3.forEach(p => { if (h.includes(p)) s += 0.10; });
  NEG.forEach(p => { if (h.includes(p)) s -= 0.20; });
  return Math.round(Math.max(0, Math.min(1, s)) * 1000) / 1000;
}

function mapCats(topic, related) {
  const h = [topic, ...related].join(' ').toLowerCase();
  const m = [];
  for (const [c, kws] of Object.entries(CAT)) {
    for (const kw of kws) {
      if (new RegExp('\\b' + kw.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + '\\b').test(h)) { m.push(c); break; }
    }
  }
  return m.length ? m : ['uncategorized'];
}

function normWords(t) {
  return new Set(t.toLowerCase().replace(/[^\w\s]/g,' ').split(/\s+/).filter(w => w && !STOP.has(w)));
}

function dedupe(items) {
  const kept = [];
  for (const c of items) {
    const cw = normWords(c.topic);
    if (!cw.size) continue;
    let di = -1;
    for (let i = 0; i < kept.length; i++) {
      const ew = normWords(kept[i].topic);
      const ov = [...cw].filter(w => ew.has(w)).length;
      const smaller = Math.min(cw.size, ew.size);
      if (smaller && ov / smaller > 0.70) { di = i; break; }
    }
    if (di === -1) kept.push(c);
    else if ((c.related_queries||[]).length > (kept[di].related_queries||[]).length) kept[di] = c;
  }
  return kept;
}

const raw = [...ytItems, ...trendsItems, ...newsItems].slice(0, 1000);

const enriched = raw.map(item => {
  const related = item.tags.slice(0, 10);
  return {
    topic: item.topic,
    traffic_estimate: 'N/A',
    source: item.source,
    related_queries: related,
    product_intent_score: scoreIntent(item.topic, related),
    suggested_categories: mapCats(item.topic, related)
  };
});

const deduped = dedupe(enriched);
deduped.sort((a, b) => b.product_intent_score - a.product_intent_score);
const ranked = deduped.map((t, i) => ({ rank: i + 1, ...t }));

const payload = {
  metadata: {
    scraped_at: new Date().toISOString(),
    geo: 'IN',
    total_topics: ranked.length,
    sources: ['google_trends_daily', 'youtube_trending', 'google_news_rss']
  },
  trends: ranked
};

console.log(`Done: ${ranked.length} topics | YT:${ytItems.length} Trends:${trendsItems.length} News:${newsItems.length}`);
return [{ json: payload }];
